mapper.select:
/* wms-outbound-order-receive-sql-oracle.xml - selectOrdSepStgCd - 주문분리 전략조회 */
SELECT
	ORDSEPSTGCD AS ORDSEPTEMPCD
	,'KOR' AS SLAKEY
FROM TWORK_INFO_ORD_SEP_STG_MSTR
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND USEYN = 'Y'

mapper.insert:
/* wms-outbound-order-receive-sql-oracle.xml - insertInterfaceOutboundHeaderReceive - 출고 헤더 수신 인터페이스 등록 */
INSERT INTO TWORK_INTF_OB_HD_RCV
(
	CTKEY
	, OWKEY
	, SOHDKEY
	, EXTERNORDERKEY
    , CLAIMNO
	, ORHDDATE
	, OBHDTYPECD
	, OBREQDATE
	, DLVYTYPECD
	, TOCTKEY
	, STOREKEY
	, DLVYFORMCD
	, NISCNLRNGCD
	, ORDPRSNNM
	, RCPPRSNNM
	, RCPPRSNTELNO
	, RCPPRSNTELNO2
	, RCPPRSNZIPCD
	, RCPPRSNADDR1
	, RCPPRSNADDR2
	, DLVYMSG
	, CHNLID
	, CMT
	, PRCSYN
	, PRCSDATE
	, RCVDATE
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
)
VALUES
(
	#{ctkey}
	,#{owkey}
	,#{orhdkey}
	,#{externorderkey}
    ,#{claimno}
	,#{obhdday}
	,#{obhdtypecd}
	,#{obreqdate}
	,#{dlvytypecd}
	,#{toctkey}
	,#{storekey}
	,#{dlvyformcd}
	,#{niscnlrngcd}
	,#{ordprsnnm}
	,#{rcpprsnnm}
	,#{rcpprsntelno}
	,#{rcpprsntelno2}
	,#{rcpprsnzipcd}
	,#{rcpprsnaddr1}
	,#{rcpprsnaddr2}
	,#{dlvymsg}
	,#{chnlid}
	,#{cmt}
	,'N'
	,NULL
	,#{sysdate}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
)

/* wms-outbound-order-receive-sql-oracle.xml - insertInterfaceOutboundDetailReceive - 출고 상세 수신 인터페이스 등록 */
