mapper.update:
UPDATE TWORK_INTF_OB_HD_RCV
SET PRCSYN = 'Y'
	,PRCSDATE = #{sysdate}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND SOHDKEY = #{orhdkey}

UPDATE TWORK_INTF_OB_DT_RCV
